mapper.select:
SELECT h.id, h.device_id, h.record_date, h.health_score, h.risk_level, h.runtime_score, h.fault_score, h.workorder_score, h.replacement_score, h.predicted_failure_days, h.confidence_level, h.algorithm_version, h.created_at, e.code AS device_code, e.name AS device_name, e.importance_level AS device_importance FROM ai_device_health h LEFT JOIN equipment e ON h.device_id = e.id WHERE h.record_date = ( SELECT MAX(record_date) FROM ai_device_health WHERE device_id = h.device_id )
AND h.risk_level = #{riskLevel}
AND e.code LIKE CONCAT('%', #{deviceCode}, '%')
ORDER BY h.health_score ASC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(DISTINCT h.device_id) FROM ai_device_health h LEFT JOIN equipment e ON h.device_id = e.id WHERE h.record_date = ( SELECT MAX(record_date) FROM ai_device_health WHERE device_id = h.device_id )
AND h.risk_level = #{riskLevel}
AND e.code LIKE CONCAT('%', #{deviceCode}, '%')
